        for (int row = 0; row < rows; row++) {
            for (int col = 0; col < cols; col++) {
                int x = col * sizeSprite;
                int y = row * sizeSprite;
                if (x + sizeSprite <= spriteSheet.getWidth() && y + sizeSprite <= spriteSheet.getHeight()) {
