        }

        boolean terrainPiercing = effectType == BulletEffectType.PIERCING;
        collisionOn = false;
        if (!terrainPiercing) {
            gp.getCollisionChecker().checkTile(this);
        }

        if (!terrainPiercing && collisionOn) {
